import axios from 'axios';

const backendURL = 'http://localhost:3000/api/auth';

// Configure axios defaults
axios.defaults.headers.common['Content-Type'] = 'application/json';
axios.defaults.withCredentials = true;

// Register a new user
export const register = async (username, email, password) => {
  try {
    console.log('Sending registration data:', { username, email, password });
    const response = await axios.post(`${backendURL}/register`, 
      { username, email, password },
      {
        headers: {
          'Content-Type': 'application/json',
        }
      }
    );
    console.log('Registration response:', response.data);
    return response.data;
  } catch (error) {
    console.error('Registration error details:', {
      message: error.message,
      response: error.response?.data,
      status: error.response?.status
    });
    throw error;
  }
};

// Login user
export const login = async (username, password) => {
    try {
        const response = await axios.post(`${backendURL}/login`, { username, password });
        return response.data;
    } catch (error) {
        console.error('Login error:', error);
        throw error;
    }
};

// Logout user
export const logout = async () => {
    try {
        const response = await axios.post(`${backendURL}/logout`);
        return response.data;
    } catch (error) {
        console.error('Logout error:', error);
        throw error;
    }
};

// Forgot password
export const forgotPassword = async (email) => {
    try {
        const response = await axios.post(`${backendURL}/forgot-password`, { email });
        return response.data;
    } catch (error) {
        console.error('Forgot password error:', error);
        throw error;
    }
};
